import AddToCartButton from "@/app/components/user components/Store/AddToCart";
import { client } from "@/utils/helper";
import Image from "next/image";

const memoryOptions = ["64GB", "128GB", "256GB", "512GB"];

export default async function ProductPage({ params }) {
  const { slug } = await params;
  const prouduct_res = await client.get(`product/slug/${slug}`);
  const product = prouduct_res?.data?.data;
  const imagePath = prouduct_res?.data?.meta?.image;

  return (
    <div className="min-h-screen bg-gray-50 p-4 md:p-6">
      <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-6 md:gap-10 bg-white p-4 md:p-6 rounded-2xl shadow-lg">
        {/* Left - Images */}
        <div>
          <div className="rounded-xl overflow-hidden border">
            <img
              src={`http://localhost:5000/product/${product?.thumbnail}`}
              alt="product"
              width={500}
              height={500}
              className="object-contain w-full max-h-[300px] md:max-h-none"
            />
          </div>

          <div className="flex gap-2 md:gap-3 mt-3 md:mt-4 flex-wrap">
            {product?.images?.map((i) => (
              <div
                key={i}
                className="w-16 h-16 md:w-20 md:h-20 border rounded-lg flex items-center justify-center cursor-pointer hover:border-[#01A49E]"
              >
                <img
                  src={`http://localhost:5000/product/${i}`}
                  alt="thumb"
                  width={60}
                  height={60}
                  className="object-contain"
                />
              </div>
            ))}
          </div>
        </div>

        {/* Right - Details */}
        <div className="flex flex-col gap-4 md:gap-5">
          <h1 className="text-xl md:text-2xl font-semibold">{product.name}</h1>

          <div className="flex items-center gap-3 flex-wrap">
            <p className="text-xl md:text-2xl font-bold text-[#01A49E]">
              ₹{product?.final_price}
            </p>
            <p className="text-gray-400 line-through text-sm md:text-base">
              ₹{product?.original_price}
            </p>
            <span className="bg-[#01A49E] text-white text-xs px-2 py-1 rounded">
              {product?.discount_percentage}% OFF
            </span>
          </div>

          <ul className="text-xs md:text-sm text-gray-600 space-y-1">
            <li>• Intel LGA 1700 Socket</li>
            <li>• DDR5 Compatible</li>
            <li>• 16+1+2 Phase Digital VRM</li>
          </ul>

          {/* Color Selection */}
          <div>
            <h3 className="font-medium mb-2 text-sm md:text-base">Color</h3>
            <div className="flex gap-2 md:gap-3 flex-wrap">
              {product?.colorId?.map((color) => (
                <button
                  key={color.name}
                  className="px-3 md:px-4 py-1.5 md:py-2 border rounded-lg text-xs md:text-sm flex items-center gap-2 border-[#01A49E] bg-[#01A49E]/10"
                >
                  <span
                    className="w-3 h-3 md:w-4 md:h-4 rounded-full"
                    style={{ backgroundColor: color.colorCode }}
                  ></span>
                  {color.name}
                </button>
              ))}
            </div>
          </div>

          {/* Promo */}
          <div className="bg-[#01A49E]/10 p-3 md:p-4 rounded-xl text-xs md:text-sm">
            <p>
              Buy <span className="text-[#01A49E] font-semibold">02</span> boxes
              get a Snack Tray
            </p>
            <p>
              Buy <span className="text-[#01A49E] font-semibold">04</span> boxes
              get a free Block Toys
            </p>
          </div>

          {/* Buttons */}
          <div className="flex gap-4 mt-2 md:mt-4">
            <AddToCartButton product={product} />
          </div>
        </div>
      </div>
    </div>
  );
}
